def longestSubsequence(self, s: str, k: int) -> int:
    n = len(s)
    dp = [0] * (k + 1)

    for i in range(n):
        for j in range(k + 1):
            if s[i] == '1':
                dp[j] = max(dp[j], dp[j - int(s[i])] + 1)
    return dp[k]

